package main

import (
	"context"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"strings"
	"sync"
	"time"

	"github.com/gorilla/websocket"
)

const (
	// Time allowed to write a message to the peer.
	writeWait = 10 * time.Second

	// Time allowed to read the next pong message from the peer.
	pongWait = 60 * time.Second

	// Send pings to peer with this period. Must be less than pongWait.
	pingPeriod = (pongWait * 9) / 10

	// Maximum message size allowed from peer.
	maxMessageSize = 512
)

// Client represents a connected user.
type Client struct {
	id     string
	conn   *websocket.Conn
	send   chan []byte // Buffered channel for outbound messages.
	roles  []string
	server *Server
	mu     sync.Mutex // Mutex for protecting client state (like roles, or send channel)
}

// HasRole checks if the client has any of the required roles.
func (c *Client) HasRole(requiredRoles ...string) bool {
	if len(requiredRoles) == 0 {
		return true // No roles required, always allowed
	}
	c.mu.Lock()
	defer c.mu.Unlock()
	for _, reqRole := range requiredRoles {
		for _, clientRole := range c.roles {
			if strings.EqualFold(clientRole, reqRole) {
				return true
			}
		}
	}
	return false
}

// SendMessage sends a message to the client.
func (c *Client) SendMessage(message interface{}) {
	data, err := json.Marshal(message)
	if err != nil {
		log.Printf("Error marshalling message for client %s: %v", c.id, err)
		return
	}
	select {
	case c.send <- data:
	default:
		// Drop message if client's send buffer is full
		log.Printf("Client %s send buffer full, dropping message", c.id)
	}
}

// readPump pumps messages from the websocket connection to the server.
func (c *Client) readPump() {
	defer func() {
		c.server.unregisterClient(c)
		c.conn.Close()
	}()
	c.conn.SetReadLimit(maxMessageSize)
	c.conn.SetReadDeadline(time.Now().Add(pongWait))
	c.conn.SetPongHandler(func(string) error { c.conn.SetReadDeadline(time.Now().Add(pongWait)); return nil })

	for {
		_, message, err := c.conn.ReadMessage()
		if err != nil {
			if websocket.IsUnexpectedCloseError(err, websocket.CloseGoingAway, websocket.CloseAbnormalClosure) {
				log.Printf("error: %v", err)
			}
			break
		}
		c.server.processClientMessage(c, message)
	}
}

// writePump pumps messages from the server to the websocket connection.
func (c *Client) writePump() {
	ticker := time.NewTicker(pingPeriod)
	defer func() {
		ticker.Stop()
		c.conn.Close()
	}()
	for {
		select {
		case message, ok := <-c.send:
			c.conn.SetWriteDeadline(time.Now().Add(writeWait))
			if !ok {
				// The server closed the channel.
				c.conn.WriteMessage(websocket.CloseMessage, []byte{})
				return
			}

			w, err := c.conn.NextWriter(websocket.TextMessage)
			if err != nil {
				return
			}
			w.Write(message)

			// Add queued chat messages to the current websocket message.
			n := len(c.send)
			for i := 0; i < n; i++ {
				w.Write([]byte{'\n'})
				w.Write(<-c.send)
			}

			if err := w.Close(); err != nil {
				return
			}
		case <-ticker.C:
			c.conn.SetWriteDeadline(time.Now().Add(writeWait))
			if err := c.conn.WriteMessage(websocket.PingMessage, nil); err != nil {
				return
			}
		}
	}
}

// Command represents a parsed command from a chat message.
type Command struct {
	Name string
	Args []string
}

// CommandHandler is the function signature for command handlers.
type CommandHandler func(client *Client, cmd *Command)

// CommandDefinition stores metadata about a command.
type CommandDefinition struct {
	Handler       CommandHandler
	RequiredRoles []string
	Description   string
}

// Message is a generic structure for messages exchanged between client and server.
type Message struct {
	Type    string                 `json:"type"`
	Content string                 `json:"content,omitempty"`
	Sender  string                 `json:"sender,omitempty"`
	Data    map[string]interface{} `json:"data,omitempty"`
}

// Server holds the state of the game server.
type Server struct {
	clients      map[string]*Client // Connected clients by ID
	register     chan *Client
	unregister   chan *Client
	broadcast    chan []byte
	commands     map[string]CommandDefinition
	mu           sync.RWMutex // Mutex for clients map
	nextClientID int
	upgrader     websocket.Upgrader
}

// NewServer creates and initializes a new server instance.
func NewServer() *Server {
	s := &Server{
		clients:    make(map[string]*Client),
		register:   make(chan *Client),
		unregister: make(chan *Client),
		broadcast:  make(chan []byte, 256), // Buffered broadcast channel
		commands:   make(map[string]CommandDefinition),
		nextClientID: 1,
		upgrader: websocket.Upgrader{
			ReadBufferSize:  1024,
			WriteBufferSize: 1024,
			CheckOrigin: func(r *http.Request) bool {
				// Allow all origins for development. In production, restrict this.
				return true
			},
		},
	}
	s.registerDefaultCommands()
	return s
}

// Run starts the server's goroutines.
func (s *Server) Run() {
	for {
		select {
		case client := <-s.register:
			s.mu.Lock()
			s.clients[client.id] = client
			s.mu.Unlock()
			log.Printf("Client %s connected. Roles: %v. Total clients: %d", client.id, client.roles, len(s.clients))
			client.SendMessage(Message{
				Type:    "system",
				Content: fmt.Sprintf("Welcome, %s! You are connected. Your roles: %v", client.id, client.roles),
			})
			s.Broadcast(Message{
				Type:    "system",
				Content: fmt.Sprintf("User %s has joined.", client.id),
			})

		case client := <-s.unregister:
			s.unregisterClient(client)

		case message := <-s.broadcast:
			s.mu.RLock()
			for _, client := range s.clients {
				select {
				case client.send <- message:
				default:
					log.Printf("Client %s send channel is full, closing connection.", client.id)
					s.unregisterClient(client) // Unregister to prevent resource leak
				}
			}
			s.mu.RUnlock()
		}
	}
}

func (s *Server) unregisterClient(client *Client) {
	s.mu.Lock()
	if _, ok := s.clients[client.id]; ok {
		delete(s.clients, client.id)
		close(client.send)
		log.Printf("Client %s disconnected. Total clients: %d", client.id, len(s.clients))
		s.Broadcast(Message{
			Type:    "system",
			Content: fmt.Sprintf("User %s has left.", client.id),
		})
	}
	s.mu.Unlock()
}

// Broadcast sends a message to all connected clients.
func (s *Server) Broadcast(message Message) {
	data, err := json.Marshal(message)
	if err != nil {
		log.Printf("Error marshalling broadcast message: %v", err)
		return
	}
	s.broadcast <- data
}

// wsHandler handles WebSocket connections.
func (s *Server) wsHandler(w http.ResponseWriter, r *http.Request) {
	// Extract role information from headers.
	// IMPORTANT: In a production environment, roles should come from an authenticated session
	// (e.g., JWT token validated server-side) NOT directly from client-provided headers.
	// This implementation trusts the client for demonstration purposes.
	rolesHeader := r.Header.Get("User-Roles")
	var clientRoles []string
	if rolesHeader != "" {
		clientRoles = strings.Split(rolesHeader, ",")
		for i := range clientRoles {
			clientRoles[i] = strings.TrimSpace(clientRoles[i])
		}
	} else {
		clientRoles = []string{"Guest"} // Default role
	}

	conn, err := s.upgrader.Upgrade(w, r, nil)
	if err != nil {
		log.Println(err)
		return
	}

	s.mu.Lock()
	clientID := fmt.Sprintf("user%d", s.nextClientID)
	s.nextClientID++
	s.mu.Unlock()

	client := &Client{
		id:     clientID,
		conn:   conn,
		send:   make(chan []byte, 256),
		roles:  clientRoles,
		server: s,
	}
	s.register <- client

	// Start goroutines for read and write operations.
	go client.writePump()
	go client.readPump()
}

// processClientMessage parses an incoming message and handles it.
func (s *Server) processClientMessage(client *Client, message []byte) {
	var msg Message
	if err := json.Unmarshal(message, &msg); err != nil {
		log.Printf("Error unmarshalling client message from %s: %v", client.id, err)
		client.SendMessage(Message{
			Type:    "error",
			Content: "Invalid message format.",
		})
		return
	}

	switch msg.Type {
	case "chat":
		s.handleChat(client, msg.Content)
	// Add other message types (e.g., "game_action", "move") here
	default:
		log.Printf("Client %s sent unknown message type: %s", client.id, msg.Type)
		client.SendMessage(Message{
			Type:    "error",
			Content: fmt.Sprintf("Unknown message type: %s", msg.Type),
		})
	}
}

// handleChat processes a chat message, checking for commands.
func (s *Server) handleChat(client *Client, chatContent string) {
	if cmd, isCommand := s.parseCommand(chatContent); isCommand {
		s.dispatchCommand(client, cmd)
	} else {
		// Regular chat message, broadcast it.
		s.Broadcast(Message{
			Type:    "chat",
			Sender:  client.id,
			Content: chatContent,
		})
	}
}

// parseCommand checks if a message is a command and parses it.
func (s *Server) parseCommand(message string) (*Command, bool) {
	if !strings.HasPrefix(message, "/") {
		return nil, false
	}
	parts := strings.Fields(message[1:]) // Remove '/' and split
	if len(parts) == 0 {
		return nil, false // Just a '/'
	}

	cmdName := strings.ToLower(parts[0])
	args := []string{}
	if len(parts) > 1 {
		args = parts[1:]
	}
	return &Command{Name: cmdName, Args: args}, true
}

// registerCommand adds a new command to the server.
func (s *Server) registerCommand(name string, handler CommandHandler, description string, requiredRoles ...string) {
	s.commands[name] = CommandDefinition{
		Handler:       handler,
		RequiredRoles: requiredRoles,
		Description:   description,
	}
}

// registerDefaultCommands sets up the initial admin commands.
func (s *Server) registerDefaultCommands() {
	s.registerCommand("kick", s.kickCommand, "Kicks a user: /kick <username> [reason]", "Admin", "Moderator")
	s.registerCommand("ban", s.banCommand, "Bans a user: /ban <username> [duration] [reason]", "Admin")
	s.registerCommand("giveitems", s.giveItemsCommand, "Gives items to a user: /giveitems <username> <itemid> <quantity>", "Admin")
	s.registerCommand("help", s.helpCommand, "Displays available commands.", "Guest", "Admin", "Moderator")
	s.registerCommand("roles", s.rolesCommand, "Displays your current roles.", "Guest", "Admin", "Moderator")
}

// dispatchCommand finds and executes the appropriate command handler.
func (s *Server) dispatchCommand(client *Client, cmd *Command) {
	cmdDef, exists := s.commands[cmd.Name]
	if !exists {
		client.SendMessage(Message{
			Type:    "system",
			Content: fmt.Sprintf("Unknown command: /%s", cmd.Name),
		})
		return
	}

	if !client.HasRole(cmdDef.RequiredRoles...) {
		client.SendMessage(Message{
			Type:    "system",
			Content: fmt.Sprintf("Permission denied: You do not have the required roles to use /%s.", cmd.Name),
		})
		return
	}

	log.Printf("Client %s (Roles: %v) executing command: /%s %v", client.id, client.roles, cmd.Name, cmd.Args)
	cmdDef.Handler(client, cmd)
}

// --- Command Implementations ---

// helpCommand lists available commands to the client based on their roles.
func (s *Server) helpCommand(client *Client, cmd *Command) {
	var availableCommands []string
	for name, def := range s.commands {
		if client.HasRole(def.RequiredRoles...) {
			availableCommands = append(availableCommands, fmt.Sprintf("/%s - %s", name, def.Description))
		}
	}
	client.SendMessage(Message{
		Type:    "system",
		Content: "Available commands:\n" + strings.Join(availableCommands, "\n"),
	})
}

// rolesCommand displays the client's current roles.
func (s *Server) rolesCommand(client *Client, cmd *Command) {
	client.mu.Lock()
	defer client.mu.Unlock()
	client.SendMessage(Message{
		Type:    "system",
		Content: fmt.Sprintf("Your roles: %v", client.roles),
	})
}

// kickCommand kicks a user from the server.
func (s *Server) kickCommand(moderator *Client, cmd *Command) {
	if len(cmd.Args) < 1 {
		moderator.SendMessage(Message{
			Type:    "system",
			Content: "Usage: /kick <username> [reason]",
		})
		return
	}

	targetUsername := cmd.Args[0]
	reason := "No reason provided"
	if len(cmd.Args) > 1 {
		reason = strings.Join(cmd.Args[1:], " ")
	}

	s.mu.RLock()
	targetClient := s.findClientByID(targetUsername)
	s.mu.RUnlock()

	if targetClient == nil {
		moderator.SendMessage(Message{
			Type:    "system",
			Content: fmt.Sprintf("User '%s' not found.", targetUsername),
		})
		return
	}

	if targetClient.id == moderator.id {
		moderator.SendMessage(Message{
			Type:    "system",
			Content: "You cannot kick yourself.",
		})
		return
	}

	log.Printf("Moderator %s is kicking %s for reason: %s", moderator.id, targetClient.id, reason)

	targetClient.SendMessage(Message{
		Type:    "system",
		Content: fmt.Sprintf("You have been kicked by %s. Reason: %s", moderator.id, reason),
	})
	s.unregisterClient(targetClient) // This will close the connection and remove from server

	s.Broadcast(Message{
		Type:    "system",
		Content: fmt.Sprintf("User %s has been kicked by %s. Reason: %s", targetClient.id, moderator.id, reason),
	})
	moderator.SendMessage(Message{
		Type:    "system",
		Content: fmt.Sprintf("Successfully kicked user %s.", targetClient.id),
	})
}

// banCommand bans a user from the server (simulation only for now).
func (s *Server) banCommand(admin *Client, cmd *Command) {
	if len(cmd.Args) < 1 {
		admin.SendMessage(Message{
			Type:    "system",
			Content: "Usage: /ban <username> [duration] [reason]",
		})
		return
	}

	targetUsername := cmd.Args[0]
	durationStr := "permanent"
	reason := "No reason provided"

	if len(cmd.Args) > 1 {
		if _, err := time.ParseDuration(cmd.Args[1]); err == nil {
			durationStr = cmd.Args[1]
			if len(cmd.Args) > 2 {
				reason = strings.Join(cmd.Args[2:], " ")
			}
		} else {
			reason = strings.Join(cmd.Args[1:], " ") // If second arg isn't a duration, it's part of the reason
		}
	}

	s.mu.RLock()
	targetClient := s.findClientByID(targetUsername)
	s.mu.RUnlock()

	log.Printf("Admin %s is banning %s for duration %s, reason: %s", admin.id, targetUsername, durationStr, reason)

	if targetClient != nil {
		if targetClient.id == admin.id {
			admin.SendMessage(Message{
				Type:    "system",
				Content: "You cannot ban yourself.",
			})
			return
		}
		targetClient.SendMessage(Message{
			Type:    "system",
			Content: fmt.Sprintf("You have been banned by %s for %s. Reason: %s", admin.id, durationStr, reason),
		})
		s.unregisterClient(targetClient) // Kicking the client if they are online
	}

	s.Broadcast(Message{
		Type:    "system",
		Content: fmt.Sprintf("User %s has been banned by %s for %s. Reason: %s", targetUsername, admin.id, durationStr, reason),
	})
	admin.SendMessage(Message{
		Type:    "system",
		Content: fmt.Sprintf("Successfully banned user %s for %s.", targetUsername, durationStr),
	})

	// In a real system, you'd add targetUsername to a persistent ban list.
}

// giveItemsCommand simulates giving items to a user.
func (s *Server) giveItemsCommand(admin *Client, cmd *Command) {
	if len(cmd.Args) < 3 {
		admin.SendMessage(Message{
			Type:    "system",
			Content: "Usage: /giveitems <username> <itemid> <quantity>",
		})
		return
	}

	targetUsername := cmd.Args[0]
	itemID := cmd.Args[1]
	quantity := cmd.Args[2] // Can parse to int if needed

	s.mu.RLock()
	targetClient := s.findClientByID(targetUsername)
	s.mu.RUnlock()

	if targetClient == nil {
		admin.SendMessage(Message{
			Type:    "system",
			Content: fmt.Sprintf("User '%s' not found.", targetUsername),
		})
		return
	}

	log.Printf("Admin %s giving %s of item %s to %s", admin.id, quantity, itemID, targetClient.id)

	// Simulate inventory update and notification
	targetClient.SendMessage(Message{
		Type:    "system",
		Content: fmt.Sprintf("You received %s x '%s' from %s!", quantity, itemID, admin.id),
	})
	admin.SendMessage(Message{
		Type:    "system",
		Content: fmt.Sprintf("Successfully gave %s x '%s' to %s.", quantity, itemID, targetClient.id),
	})

	// In a real system, this would interact with a game state/database
}

// findClientByID helper function to get a client by their ID.
func (s *Server) findClientByID(id string) *Client {
	for _, client := range s.clients {
		if client.id == id {
			return client
		}
	}
	return nil
}

func main() {
	server := NewServer()
	go server.Run()

	http.HandleFunc("/ws", server.wsHandler)
	http.HandleFunc("/", func(w http.ResponseWriter, r *http.Request) {
		http.ServeFile(w, r, "index.html")
	})

	log.Println("Server started on :8080")
	log.Println("Access WebSocket at ws://localhost:8080/ws")
	log.Fatal(http.ListenAndServe(":8080", nil))
}

